const items = $input.all();
const results = [];

for (const item of items) {
  const raw = item.json;
  const input = raw.body || raw;

  if (!input.issue_id) throw new Error('Missing issue_id');
  if (!input.subject) throw new Error('Missing subject');
  if (!input.body_html) throw new Error('Missing body_html');

  results.push({
    json: {
      issue_id: input.issue_id,
      to: input.to || '',
      authority: input.authority || 'Stadtverwaltung',
      subject: input.subject,
      body_html: input.body_html
    }
  });
}

return results;

